mapper.select:

select id,
	   first_name ,
	   last_name ,
	   age,
	   status
	   from student
	   where 1=1 

	   and id=#{id}


	   	and first_name = #{firstName}


	   	and last_name = #{lastName}


	   and 
	   (first_name LIKE #{condition}
	   OR last_name LIKE #{condition}
	   )


	   and age=#{age}


	   and status=#{status}


